import{_ as a,o as t,c as o,j as r,a as n,a1 as p}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"电光人","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/2.改造与功法/改造/6.一次性改造/电光人.md","filePath":"4.资源分区/2.改造与功法/改造/6.一次性改造/电光人.md"}'),s={name:"4.资源分区/2.改造与功法/改造/6.一次性改造/电光人.md"};function b(d,e,l,_,i,c){return t(),o("div",null,[...e[0]||(e[0]=[r("h1",{id:"电光人",tabindex:"-1"},[n("电光人 "),r("a",{class:"header-anchor",href:"#电光人","aria-label":'Permalink to "电光人"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘004C")])])],-1),p('<h1 id="电光人-1" tabindex="-1">电光人 <a class="header-anchor" href="#电光人-1" aria-label="Permalink to &quot;电光人&quot;">​</a></h1><p>电光人<br> B+2400<br> 特异本质</p><p>“U`re not nobody，U`re a somebody.”<br> “你并不是无名小将，你是个大人物。”<br> 最初的电光人是在意外中获得了储存和控制电的能力，当他初次看到漫天电光时，这个世界让他感觉陌生。</p><p>你获得了一种新的视觉能力，你能够看到空气及物体中的电能流动，这视为侦测等级为C，科技本质的侦测效果。你能够看到某些以电磁波形式存在的灵体/虚体，这视为你获得了灵感视觉。</p><p>你获得一个特殊的能量池【电能】，本资源下的电能均指向本改造提供的电能。<br> 电能只能被你从外界吸收，你无法自行产生这一能量。<br> 你可以吸收电能，包括来自科技本质的电能，来自自然本质的电能以及来自魔幻本质的电能，吸收电能的目标需要是不可自主行动的。<br> 你可以将吸收的电能用于给其他需求电力的设备供电，你储备电能的上限为48万度，相当于一个20MW发电机一天满负荷发电。<br> 吸收电能是一个标准动作，你可以吸收当前触及物体内含有的电能，每一轮最多吸收5万度电或等同于10点能量的电力。<br> 你身体内储存的最低电能为1000度，若低于此数值，每低100度则受到一点不可豁免的疲乏点数（不足100按100计算）。</p><p>你的攻击全部具有【法破】特性，你可以在任何具有攻击描述的检定前以一个自由动作发出声明，使你的本次攻击的伤害变为雷电伤害，若你如此做，则本次攻击检定获得【接触攻击】特性以及3点来自能量的附加成功。<br> 若你原本使用的攻击造成的伤害类型是雷电，则来自能量的附加成功提升至4。<br> 启用本效果，消耗一万度电能储备。</p><p>你获得了一种移动方式——【浴电疾走】：消耗5000度电能与一个移动动作进行一次移动，这次移动的速度翻倍，你在战斗中使用本能力后进行的第一次攻击具有B级措手不及。特殊的，使用这一移动方式需要满足以下条件：1、处于具有电能的环境中。2、移动的起始点与终点相互之间具有电路链接。<br> *具有电能的环境：这一环境中需要有大量的电能存在，比如：现代都市、高压电线下、雷雨天。当然你也可以借助发电机布置电子线路并铺设在一个场景中（可能需要经过一定的周期检定），这样也可以满足电能环境的要求，不过一旦电力源头被切断，这一环境也会自动消失。</p><p>主神牌火力发电机<br> 50<br> 每日发电需要供给价值1点的燃料。<br> 折叠体积4<br> 展开体积16<br> 结构值 7<br> 装甲 3<br> 展开这一发电机需要10分钟的准备时间，收起这一发电机也是如此。<br> 展开后的发电机在燃料充足的情况下每小时能产生2万度电。</p><p>无限能源火力发电机500点。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',11)])])}const m=a(s,[["render",b]]);export{f as __pageData,m as default};
